"""FastMCP server: GreenNode AgentBase helper with list_available_guides and read_guide_page tools."""

from __future__ import annotations

from . import cache, fetch
from .config import get_docs_base_url
from .guides import AVAILABLE_GUIDES


def _subpath_from_guide_arg(guide: str) -> str:
    """Extract subpath from guide string (either 'subpath - reason' or just 'subpath')."""
    s = guide.strip()
    if " - " in s:
        return s.split(" - ", 1)[0].strip()
    return s


def _url_for_subpath(subpath: str) -> str:
    """Build full URL for a subpath (base URL without trailing slash + / + subpath)."""
    base = get_docs_base_url().rstrip("/")
    sub = subpath.lstrip("/")
    return f"{base}/{sub}" if sub else base


def _get_markdown_for_url(url: str) -> str:
    """Return markdown for URL: from cache or fetch, convert, and cache."""
    cached = cache.get_cached_markdown(url)
    if cached is not None:
        return cached
    markdown = fetch.fetch_url_as_markdown(url)
    if markdown:
        cache.set_cached_markdown(url, markdown)
    return markdown


def _create_app():  # noqa: D103
    from fastmcp import FastMCP

    mcp = FastMCP("GreenNode AgentBase Helper")

    @mcp.tool()
    def list_available_guides() -> str:
        """List available guide pages. Each entry is 'subpath - reason'. Use read_guide_page with the subpath or full entry to read content."""
        return "\n".join(AVAILABLE_GUIDES) if AVAILABLE_GUIDES else "No guides configured."

    @mcp.tool()
    def read_guide_page(guide: str) -> str:
        """Read a guide page as markdown. Pass the subpath (e.g. 'getting-started') or a full list entry (e.g. 'getting-started - How to get started')."""
        subpath = _subpath_from_guide_arg(guide)
        if not subpath:
            return "Error: guide identifier or subpath is required."
        url = _url_for_subpath(subpath)
        markdown = _get_markdown_for_url(url)
        if not markdown:
            return f"Could not fetch or convert content from {url}."
        return markdown

    return mcp


# Lazy app instance so optional deps are only required when MCP is used.
_app: object | None = None


def get_app():
    """Return the FastMCP app instance (creates on first use)."""
    global _app
    if _app is None:
        _app = _create_app()
    return _app
